using namespace std;

const long long INF = 1e18;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    int kk = static_cast<int>(k);

    if (m == 0 || n == 0) return 0;

    vector<vector<vector<long long>>> dp(m, vector<vector<long long>>(n, vector<long long>(kk+1, INF)));
    dp[0][0][0] = 0;

    for (int t = 0; t <= kk; t++) {
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (i > 0) {
                    long long cost = dp[i-1][j][t] + grid[i][j];
                    if (cost < dp[i][j][t]) {
                        dp[i][j][t] = cost;
                    }
                }
                if (j > 0) {
                    long long cost = dp[i][j-1][t] + grid[i][j];
                    if (cost < dp[i][j][t]) {
                        dp[i][j][t] = cost;
                    }
                }
            }
        }

        if (t < kk) {
            long long max_val = 0;
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    if (grid[i][j] > max_val) {
                        max_val = grid[i][j];
                    }
                }
            }

            vector<long long> F(max_val+1, INF);
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    long long value = grid[i][j];
                    if (value <= max_val) {
                        if (dp[i][j][t] < F[value]) {
                            F[value] = dp[i][j][t];
                        }
                    }
                }
            }

            vector<long long> S(max_val+1, INF);
            if (max_val >= 0) {
                S[max_val] = F[max_val];
                for (int v = max_val-1; v >= 0; v--) {
                    S[v] = min(F[v], S[v+1]);
                }
            }

            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    long long val = grid[i][j];
                    if (val <= max_val) {
                        long long candidate = S[val];
                        if (candidate < dp[i][j][t+1]) {
                            dp[i][j][t+1] = candidate;
                        }
                    }
                }
            }
        }
    }

    long long ans = INF;
    for (int t = 0; t <= kk; t++) {
        if (dp[m-1][n-1][t] < ans) {
            ans = dp[m-1][n-1][t];
        }
    }
    return ans;
}
