#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>
#include <climits>
using namespace std;

const int MAX_VAL = 10000;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();

    int K = (int)k;
    long long INF = 1LL << 60;

    vector<vector<vector<long long>>> dp(K+1, vector<vector<long long>>(m, vector<long long>(n, INF)));

    vector<priority_queue<tuple<long long, int, int>, vector<tuple<long long, int, int>>, greater<tuple<long long, int, int>>>> pq(K+1);

    int dirs[2][2] = {{0, 1}, {1, 0}};

    dp[0][0][0] = 0;
    pq[0].push(make_tuple(0, 0, 0));

    for (int t = 0; t <= K; t++) {
        while (!pq[t].empty()) {
            auto [cost, i, j] = pq[t].top();
            pq[t].pop();

            if (cost != dp[t][i][j])
                continue;

            for (auto &d : dirs) {
                int ni = i + d[0];
                int nj = j + d[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long long new_cost = cost + grid[ni][nj];
                    if (new_cost < dp[t][ni][nj]) {
                        dp[t][ni][nj] = new_cost;
                        pq[t].push(make_tuple(new_cost, ni, nj));
                    }
                }
            }
        }

        if (t < K) {
            vector<long long> min_dp_local(MAX_VAL + 1, INF);
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    long long val_ll = grid[i][j];
                    if (val_ll < 0 || val_ll > MAX_VAL)
                        continue;
                    int val = static_cast<int>(val_ll);
                    if (dp[t][i][j] < min_dp_local[val]) {
                        min_dp_local[val] = dp[t][i][j];
                    }
                }
            }

            vector<long long> min_dp(MAX_VAL + 1, INF);
            long long min_so_far = INF;
            for (int v = MAX_VAL; v >= 0; v--) {
                min_so_far = min(min_so_far, min_dp_local[v]);
                min_dp[v] = min_so_far;
            }

            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    long long val_ll = grid[i][j];
                    if (val_ll < 0 || val_ll > MAX_VAL)
                        continue;
                    int val = static_cast<int>(val_ll);
                    long long candidate = min_dp[val];
                    if (candidate < dp[t+1][i][j]) {
                        dp[t+1][i][j] = candidate;
                        pq[t+1].push(make_tuple(candidate, i, j));
                    }
                }
            }
        }
    }

    long long ans = INF;
    for (int t = 0; t <= K; t++) {
        if (dp[t][m-1][n-1] < ans) {
            ans = dp[t][m-1][n-1];
        }
    }
    return ans;
}
